ALTER TABLE profiles ENABLE ROW LEVEL SECURITY; ALTER TABLE topics ENABLE ROW LEVEL SECURITY; ALTER TABLE words ENABLE ROW LEVEL SECURITY; ALTER TABLE user_words ENABLE ROW LEVEL SECURITY; ALTER TABLE review_logs ENABLE ROW LEVEL SECURITY; ALTER TABLE sessions ENABLE ROW LEVEL SECURITY; ALTER TABLE word_reports ENABLE ROW LEVEL SECURITY; ALTER TABLE achievements ENABLE ROW LEVEL SECURITY; ALTER TABLE user_achievements ENABLE ROW LEVEL SECURITY; ALTER TABLE leaderboard_cache ENABLE ROW LEVEL SECURITY; ALTER TABLE push_subscriptions ENABLE ROW LEVEL SECURITY;
CREATE POLICY "Users read own profile" ON profiles FOR SELECT USING (auth.uid() = id OR EXISTS (SELECT 1 FROM profiles p WHERE p.id=auth.uid() AND p.role='admin'));
CREATE POLICY "Users update own profile" ON profiles FOR UPDATE USING (auth.uid() = id);
CREATE POLICY "Public read topics" ON topics FOR SELECT USING (true);
CREATE POLICY "Public read active words" ON words FOR SELECT USING (is_active = true OR EXISTS (SELECT 1 FROM profiles WHERE id=auth.uid() AND role='admin'));
CREATE POLICY "Admin manage words" ON words FOR ALL USING (EXISTS (SELECT 1 FROM profiles WHERE id=auth.uid() AND role='admin')) WITH CHECK (EXISTS (SELECT 1 FROM profiles WHERE id=auth.uid() AND role='admin'));
CREATE POLICY "Users manage own words" ON user_words FOR ALL USING (auth.uid() = user_id) WITH CHECK (auth.uid() = user_id);
CREATE POLICY "Users insert own logs" ON review_logs FOR INSERT WITH CHECK (auth.uid() = user_id); CREATE POLICY "Users read own logs" ON review_logs FOR SELECT USING (auth.uid() = user_id OR EXISTS (SELECT 1 FROM profiles WHERE id=auth.uid() AND role='admin'));
CREATE POLICY "Users manage own sessions" ON sessions FOR ALL USING (auth.uid() = user_id) WITH CHECK (auth.uid() = user_id);
CREATE POLICY "Users create own reports" ON word_reports FOR INSERT WITH CHECK (auth.uid() = user_id); CREATE POLICY "Users read own reports or admin" ON word_reports FOR SELECT USING (auth.uid() = user_id OR EXISTS (SELECT 1 FROM profiles WHERE id=auth.uid() AND role='admin')); CREATE POLICY "Admin update reports" ON word_reports FOR UPDATE USING (EXISTS (SELECT 1 FROM profiles WHERE id=auth.uid() AND role='admin'));
CREATE POLICY "Public read achievements" ON achievements FOR SELECT USING (true); CREATE POLICY "Users read own achievements" ON user_achievements FOR SELECT USING (auth.uid() = user_id); CREATE POLICY "Users read leaderboard" ON leaderboard_cache FOR SELECT USING (true); CREATE POLICY "Users manage own push" ON push_subscriptions FOR ALL USING (auth.uid() = user_id) WITH CHECK (auth.uid() = user_id);
CREATE OR REPLACE FUNCTION prevent_review_logs_mutation() RETURNS TRIGGER AS $$ BEGIN RAISE EXCEPTION 'review_logs is append-only'; END; $$ LANGUAGE plpgsql; CREATE TRIGGER no_review_logs_update BEFORE UPDATE OR DELETE ON review_logs FOR EACH ROW EXECUTE FUNCTION prevent_review_logs_mutation();
